 38→        const match = textUpToCursor.match(MENTION_REGEX);
 39→
 40→        if (!match) return;
 41→
 42→        const beforeMention = textUpToCursor.slice(0, match.index);
 43→        const afterCursor = value.slice(cursorPos);
 44→        const newValue = `${beforeMention}@${username} ${afterCursor}`;
 45→
 46→        if (newValue.length > maxLength) return;
 47→
 48→        setValue(newValue);
 49→        close();
 50→
 51→        const newCursorPos = beforeMention.length + username.length + 2;
 52→        requestAnimationFrame(() => {
 53→            if (textareaRef.current) {
 54→                textareaRef.current.focus();
