 7→const useMentionAutocomplete = (text, cursorPos) => {
 8→    const [results, setResults] = useState([]);
 9→    const [selectedIndex, setSelectedIndex] = useState(0);
10→    const [isOpen, setIsOpen] = useState(false);
11→    const [query, setQuery] = useState('');
12→    const debounceRef = useRef(null);
13→    const abortRef = useRef(null);
14→
15→    useEffect(() => {
16→        const textUpToCursor = text.slice(0, cursorPos);
17→        const match = textUpToCursor.match(MENTION_REGEX);
18→
19→        if (!match || match[1].length === 0) {
20→            setIsOpen(false);
21→            setResults([]);
22→            setQuery('');
23→            setSelectedIndex(0);
24→            return;
25→        }
26→
27→        const q = match[1];
28→        setQuery(q);
29→
30→        if (debounceRef.current) clearTimeout(debounceRef.current);
31→
32→        debounceRef.current = setTimeout(async () => {
33→            try {
34→                const res = await searchUsers(q, 6);
35→                if (res?.data && res.data.length > 0) {
36→                    setResults(res.data);
37→                    setSelectedIndex(0);
38→                    setIsOpen(true);
39→                } else {
40→                    setIsOpen(false);
41→                    setResults([]);
42→                }
43→            } catch {
44→                setIsOpen(false);
45→                setResults([]);
46→            }
47→        }, DEBOUNCE_MS);
48→
49→        return () => {
50→            if (debounceRef.current) clearTimeout(debounceRef.current);
51→        };
52→    }, [text, cursorPos]);
53→
54→    const close = useCallback(() => {
55→        setIsOpen(false);
56→        setResults([]);
57→        setSelectedIndex(0);
58→    }, []);
59→
60→    const moveUp = useCallback(() => {
61→        setSelectedIndex((prev) => (prev > 0 ? prev - 1 : results.length - 1));
62→    }, [results.length]);
63→
64→    const moveDown = useCallback(() => {
65→        setSelectedIndex((prev) => (prev < results.length - 1 ? prev + 1 : 0));
66→    }, [results.length]);
67→
68→    return {
69→        results,
70→        selectedIndex,
71→        setSelectedIndex,
72→        isOpen,
73→        query,
74→        close,
75→        moveUp,
76→        moveDown,
77→    };
78→};
